// Migration: Add question bank and answer history tables, seed with initial questions
const { neon } = require('@neondatabase/serverless');

const SEED_QUESTIONS = [{"id":"time-1","pillar":"time","sub_category":"Time Awareness","field_name":"timeAwareness","question":"How accurately can you account for where your 168 weekly hours actually go?","description":"This measures whether you know the truth about your time — not what you think happens, but what actually happens.","options":[{"value":1,"label":"No idea","description":"I couldn't tell you where last Tuesday went if you asked."},{"value":2,"label":"Vague sense","description":"I know the big blocks (work, sleep) but the rest is a blur."},{"value":3,"label":"Reasonable estimate","description":"I could account for maybe 70% of my time with fair accuracy."},{"value":4,"label":"Strong awareness","description":"I track most of my time and know where the gaps are."},{"value":5,"label":"Precision-level","description":"I've run a time audit. I know exactly where my hours go."}],"is_overlay":false,"overlay_type":null,"sort_order":1},{"id":"time-2","pillar":"time","sub_category":"Time Allocation","field_name":"timeAllocation","question":"How much of your weekly time is spent on activities that directly move you toward your most important goals?","description":"This is about Quadrant 2 activities — important but not urgent. The things that compound over time.","options":[{"value":1,"label":"Almost none","description":"My days are consumed by other people's priorities and distractions."},{"value":2,"label":"Under 10%","description":"I squeeze in meaningful work when I can, but it's rare."},{"value":3,"label":"Around 25%","description":"I make some intentional time, but urgency still dominates."},{"value":4,"label":"Around 40%","description":"My most important work gets scheduled first, most weeks."},{"value":5,"label":"50%+","description":"My calendar is built around my highest-value priorities."}],"is_overlay":false,"overlay_type":null,"sort_order":2},{"id":"time-3","pillar":"time","sub_category":"Time Protection","field_name":"timeProtection","question":"How well do you protect your peak productive hours from interruptions, low-value tasks, and other people's agendas?","description":"Your peak hours are when you do your best thinking, creating, and decision-making. Are they guarded?","options":[{"value":1,"label":"Not at all","description":"My schedule is at the mercy of whoever needs me next."},{"value":2,"label":"Occasionally","description":"I try, but I cave to requests and distractions easily."},{"value":3,"label":"Sometimes","description":"I block time but frequently allow it to be overridden."},{"value":4,"label":"Consistently","description":"My peak hours are usually protected. People know not to interrupt."},{"value":5,"label":"Non-negotiable","description":"My peak hours are sacred. I've built systems to enforce this."}],"is_overlay":false,"overlay_type":null,"sort_order":3},{"id":"time-4","pillar":"time","sub_category":"Time Leverage","field_name":"timeLeverage","question":"How effectively do you multiply your time through delegation, automation, or systems?","description":"One hour of your time should produce more than one hour of results. This measures your multiplier.","options":[{"value":1,"label":"I do everything myself","description":"If I don't do it, it doesn't get done."},{"value":2,"label":"Minimal delegation","description":"I've handed off a few things but still carry most of the load."},{"value":3,"label":"Some systems","description":"I use tools and occasionally delegate, but there's a lot of room to grow."},{"value":4,"label":"Active delegation","description":"I regularly delegate and have systems that handle repeatable tasks."},{"value":5,"label":"Highly leveraged","description":"My time is primarily spent on decisions and strategy. Systems handle execution."}],"is_overlay":false,"overlay_type":null,"sort_order":4},{"id":"time-5","pillar":"time","sub_category":"Five-Hour Leak","field_name":"fiveHourLeak","question":"Can you identify the 5+ hours you lose every week to low-value activities?","description":"Most people leak at least 5 hours weekly to scrolling, unnecessary meetings, or tasks someone else should handle. This is the Time Audit's first target (Tool #2).","options":[{"value":1,"label":"Never looked","description":"I have no idea where the leaks are. I just feel busy all the time."},{"value":2,"label":"Vague suspicion","description":"I know I waste time but couldn't name the exact activities or hours."},{"value":3,"label":"Identified some","description":"I can name 2-3 time leaks but haven't systematically tracked them."},{"value":4,"label":"Clear picture","description":"I've audited my time and know exactly where my biggest leaks are."},{"value":5,"label":"Plugged the leaks","description":"I identified and eliminated or reduced my major time leaks. I audit regularly."}],"is_overlay":false,"overlay_type":null,"sort_order":5},{"id":"time-6","pillar":"time","sub_category":"Value Per Hour","field_name":"valuePerHour","question":"Do you know your actual Value Per Hour — and are you actively working to increase it?","description":"Your Value Per Hour is what your time is actually worth in the marketplace right now. Not your salary divided by 40 — your real productive output value (Tool #5).","options":[{"value":1,"label":"No clue","description":"I've never calculated what an hour of my time is actually worth."},{"value":2,"label":"Rough guess","description":"I could ballpark it but I've never done the real math."},{"value":3,"label":"Know the number","description":"I've calculated it, but I'm not actively working to increase it."},{"value":4,"label":"Tracking it","description":"I know my VPH and I make decisions based on whether activities meet that threshold."},{"value":5,"label":"Optimizing it","description":"I know my VPH, I refuse work below it, and I'm systematically increasing it."}],"is_overlay":false,"overlay_type":null,"sort_order":6},{"id":"time-7","pillar":"time","sub_category":"Time Investment","field_name":"timeInvestment","question":"Do you treat your time as an investment with expected returns — or as an expense you just burn through?","description":"Investors expect ROI. Spenders just watch the balance go down. Which one describes your relationship with time?","options":[{"value":1,"label":"Pure expense","description":"Time just passes. I don't think about returns on how I spend it."},{"value":2,"label":"Mostly expense","description":"I occasionally think about ROI but most of my time is unaccounted for."},{"value":3,"label":"Mixed","description":"Some of my time is invested intentionally, but a lot still just gets spent."},{"value":4,"label":"Mostly invested","description":"I evaluate most activities by their time ROI before committing."},{"value":5,"label":"Full investor mindset","description":"Every significant time block is allocated with expected returns. I track outcomes."}],"is_overlay":false,"overlay_type":null,"sort_order":7},{"id":"time-8","pillar":"time","sub_category":"Downtime Quality","field_name":"downtimeQuality","question":"Are your dreams worth your downtime — or is 'someday' stealing your today?","description":"Downtime should recharge you for high-value work, not become a trap where ambition goes to die. The 'someday' peril is real.","options":[{"value":1,"label":"Trapped in someday","description":"I spend most of my free time on things that feel good now but build nothing."},{"value":2,"label":"Mostly wasted","description":"My downtime is mostly consumption — TV, scrolling, avoiding hard things."},{"value":3,"label":"Balanced","description":"Some of my downtime recharges me, but I still lose a lot to passive habits."},{"value":4,"label":"Intentional rest","description":"My downtime is deliberate — I rest to recharge, not to escape."},{"value":5,"label":"Strategic recovery","description":"My rest fuels my work. My dreams drive how I spend every hour, including downtime."}],"is_overlay":false,"overlay_type":null,"sort_order":8},{"id":"time-9","pillar":"time","sub_category":"Foresight","field_name":"foresight","question":"How well do you see and plan for what's coming — instead of constantly reacting to what already happened?","description":"Foresight is 20/20 vision for the future. Reactive people fight fires. Proactive people prevent them.","options":[{"value":1,"label":"Fully reactive","description":"I spend most of my energy dealing with problems I didn't see coming."},{"value":2,"label":"Mostly reactive","description":"I handle crises well but rarely see them before they arrive."},{"value":3,"label":"Developing foresight","description":"I'm getting better at anticipating, but I still get blindsided regularly."},{"value":4,"label":"Proactive planner","description":"I plan ahead for most scenarios and rarely get caught off guard."},{"value":5,"label":"Strategic foresight","description":"I consistently anticipate challenges and opportunities 90+ days out. I build systems for it."}],"is_overlay":false,"overlay_type":null,"sort_order":9},{"id":"time-10","pillar":"time","sub_category":"Time Reallocation","field_name":"timeReallocation","question":"How actively do you move time away from low-value activities and toward high-value ones?","description":"It's not enough to know where your time goes. The Value Engine demands you reallocate it — deliberately moving hours from what drains you to what compounds (Tool #9).","options":[{"value":1,"label":"No movement","description":"My schedule hasn't meaningfully changed in months despite knowing it should."},{"value":2,"label":"Small shifts","description":"I've made a few changes but most of my low-value habits persist."},{"value":3,"label":"Active adjusting","description":"I regularly try to shift time but old patterns pull me back."},{"value":4,"label":"Consistent reallocation","description":"I've successfully moved significant time from low to high-value activities."},{"value":5,"label":"Continuous optimization","description":"I treat time reallocation as an ongoing practice. I audit and adjust monthly."}],"is_overlay":false,"overlay_type":null,"sort_order":10},{"id":"people-1","pillar":"people","sub_category":"Trust Investment","field_name":"trustInvestment","question":"How intentionally do you invest trust in the people around you — based on evidence, not emotion?","description":"Trust is a currency. Are you spending it wisely, or giving it away to anyone who asks?","options":[{"value":1,"label":"No filter","description":"I trust people too easily and it costs me regularly."},{"value":2,"label":"Learning the hard way","description":"I've been burned enough to be cautious, but I still misjudge."},{"value":3,"label":"Developing discernment","description":"I evaluate people before extending deep trust, but I miss red flags."},{"value":4,"label":"Evidence-based","description":"I extend trust incrementally based on demonstrated behavior."},{"value":5,"label":"Strategic investor","description":"I know exactly who deserves what level of access and I manage it deliberately."}],"is_overlay":false,"overlay_type":null,"sort_order":11},{"id":"people-2","pillar":"people","sub_category":"Boundary Quality","field_name":"boundaryQuality","question":"How clear and enforced are your boundaries with the people in your life?","description":"Boundaries aren't walls — they're the terms of engagement that protect your most valuable resources.","options":[{"value":1,"label":"No boundaries","description":"People take what they want from me and I allow it."},{"value":2,"label":"Weak boundaries","description":"I set them sometimes but back down when challenged."},{"value":3,"label":"Inconsistent","description":"I have boundaries in some areas but not others. Enforcement is spotty."},{"value":4,"label":"Clear and communicated","description":"Most people in my life know my limits and I hold them."},{"value":5,"label":"Firm and respected","description":"My boundaries are non-negotiable. People respect them because I enforce them."}],"is_overlay":false,"overlay_type":null,"sort_order":12},{"id":"people-3","pillar":"people","sub_category":"Network Depth","field_name":"networkDepth","question":"How deep and meaningful are the relationships in your inner circle?","description":"It's not about how many people you know. It's about how many of those relationships produce mutual value.","options":[{"value":1,"label":"Surface-level","description":"Most of my relationships are transactional or shallow."},{"value":2,"label":"A few real ones","description":"I have 1-2 deep relationships but most are surface."},{"value":3,"label":"Growing","description":"I'm building deeper connections but it takes effort."},{"value":4,"label":"Solid core","description":"I have 5+ relationships with real trust, vulnerability, and mutual investment."},{"value":5,"label":"Deep network","description":"My inner circle is intentionally built with people who challenge, support, and grow with me."}],"is_overlay":false,"overlay_type":null,"sort_order":13},{"id":"people-4","pillar":"people","sub_category":"Relational ROI","field_name":"relationalRoi","question":"If you mapped the return on investment from your closest relationships, what would the data show?","description":"Not all relationships are equal. Some compound. Some drain. This measures which type dominates your life.","options":[{"value":1,"label":"Net negative","description":"Most of my relational energy goes to people who take more than they give."},{"value":2,"label":"Breaking even","description":"It balances out, but I'm not growing from these relationships."},{"value":3,"label":"Modest return","description":"Some relationships are clearly positive, but others drag me down."},{"value":4,"label":"Strong returns","description":"The majority of my relational investments are producing growth and opportunity."},{"value":5,"label":"Compounding","description":"My relationships actively multiply my opportunities, knowledge, and influence."}],"is_overlay":false,"overlay_type":null,"sort_order":14},{"id":"people-5","pillar":"people","sub_category":"People Audit","field_name":"peopleAudit","question":"Have you mapped the people in your life against the four types: Givers, Receivers, Exchangers, and Takers?","description":"The People Audit (Tool #3) forces you to see who's actually in your life and what role they play. Most people have never done this honestly.","options":[{"value":1,"label":"Never considered it","description":"I've never categorized the people around me. I just deal with whoever shows up."},{"value":2,"label":"Intuitive sense","description":"I could probably guess who falls where, but I've never mapped it out."},{"value":3,"label":"Partially mapped","description":"I've thought about my closest relationships but haven't done the full audit."},{"value":4,"label":"Mostly mapped","description":"I know who the Givers, Exchangers, and Takers are in my top 15 relationships."},{"value":5,"label":"Fully audited","description":"I've completed a People Audit. I know exactly who deposits and who withdraws."}],"is_overlay":false,"overlay_type":null,"sort_order":15},{"id":"people-6","pillar":"people","sub_category":"Alliance Building","field_name":"allianceBuilding","question":"How well do you build and maintain your four types of alliances: Confidants, Constituents, Comrades, and Companions?","description":"The 4 Alliances framework (Tool #6) maps who is for you, for your cause, or just along for the ride. Each type serves a different function.","options":[{"value":1,"label":"No strategy","description":"I don't think about relationship types. People are just... people."},{"value":2,"label":"Emerging awareness","description":"I can see different levels of trust but I don't manage them intentionally."},{"value":3,"label":"Some structure","description":"I know who my closest allies are but I haven't mapped the full alliance picture."},{"value":4,"label":"Intentional alliances","description":"I invest differently in Confidants vs. Comrades and manage expectations accordingly."},{"value":5,"label":"Strategic network","description":"I've built and maintain all four alliance types. Each relationship has a clear role and investment level."}],"is_overlay":false,"overlay_type":null,"sort_order":16},{"id":"people-7","pillar":"people","sub_category":"Love Bank Deposits","field_name":"loveBankDeposits","question":"In your most important relationships, are you making more deposits than withdrawals in the Love Bank?","description":"Harley's Love Bank concept: every interaction is a deposit or withdrawal. When the balance goes negative, the relationship dies — sometimes silently.","options":[{"value":1,"label":"Overdrawn","description":"I'm taking more than I give in most of my key relationships."},{"value":2,"label":"Near zero","description":"Some relationships are in the red. I know I need to deposit more."},{"value":3,"label":"Breaking even","description":"I try to give back but I'm not tracking whether I'm ahead or behind."},{"value":4,"label":"Net positive","description":"I make intentional deposits in my key relationships regularly."},{"value":5,"label":"Abundant deposits","description":"My closest relationships have deep reserves because I invest consistently and intentionally."}],"is_overlay":false,"overlay_type":null,"sort_order":17},{"id":"people-8","pillar":"people","sub_category":"Communication Clarity","field_name":"communicationClarity","question":"How well do you use the Communicate, Clarify, Question framework in your key relationships?","description":"Most conflict comes from unclear communication. The framework: state it clearly, verify they understood it, then ask the question that reveals their real concern.","options":[{"value":1,"label":"Chaotic communicator","description":"I say what I think and assume people get it. They usually don't."},{"value":2,"label":"Improving","description":"I know I'm unclear sometimes but I catch it after the damage is done."},{"value":3,"label":"Decent clarity","description":"I communicate well in calm situations but break down under pressure."},{"value":4,"label":"Intentional communicator","description":"I regularly check for understanding and ask clarifying questions before reacting."},{"value":5,"label":"Master communicator","description":"I use the full framework — communicate, clarify, question — as a habit in all important conversations."}],"is_overlay":false,"overlay_type":null,"sort_order":18},{"id":"people-9","pillar":"people","sub_category":"Restraint Practice","field_name":"restraintPractice","question":"How often do you apply the Four Questions Before You Speak?","description":"Before you speak: Is it true? Is it kind? Is it necessary? Is it the right time? Most relational damage comes from skipping these filters.","options":[{"value":1,"label":"Speak first, think later","description":"I say what comes to mind and deal with the fallout after."},{"value":2,"label":"Occasional filter","description":"I catch myself sometimes but words still escape before I think."},{"value":3,"label":"Working on it","description":"I'm more careful than I used to be but I still slip under pressure."},{"value":4,"label":"Disciplined","description":"I pause before speaking in most important moments and run my words through a filter."},{"value":5,"label":"Mastered restraint","description":"I rarely speak without considering truth, kindness, necessity, and timing. It's automatic."}],"is_overlay":false,"overlay_type":null,"sort_order":19},{"id":"people-10","pillar":"people","sub_category":"Value Replacement","field_name":"valueReplacement","question":"Are you actively redirecting relational energy from low-ROI to high-ROI relationships?","description":"The Value Replacement Map (Tool #10): don't just cut toxic people — replace that energy with relationships that compound. Nature abhors a vacuum.","options":[{"value":1,"label":"Stuck in low-ROI","description":"Most of my relational energy goes to people who drain me, but I don't know how to change."},{"value":2,"label":"Aware but stuck","description":"I know which relationships are draining but I haven't redirected the energy yet."},{"value":3,"label":"Starting to shift","description":"I've reduced some low-ROI interactions but haven't fully replaced them with better ones."},{"value":4,"label":"Active replacement","description":"I'm deliberately spending less time with drainers and more with growers."},{"value":5,"label":"Fully reallocated","description":"My relational energy is invested where it compounds. I've replaced low-ROI connections with high-ROI ones."}],"is_overlay":false,"overlay_type":null,"sort_order":20},{"id":"influence-1","pillar":"influence","sub_category":"Leadership Level","field_name":"leadershipLevel","question":"At what level do people follow your leadership?","description":"Based on Maxwell's five levels: Position (they have to), Permission (they want to), Production (you deliver), People Development (you grow them), Pinnacle (respect).","options":[{"value":1,"label":"Position only","description":"People follow because of my title or role — not by choice."},{"value":2,"label":"Permission","description":"People follow because they like me and we have a relationship."},{"value":3,"label":"Production","description":"People follow because I produce results and deliver on commitments."},{"value":4,"label":"People Development","description":"People follow because I invest in growing them and they've seen real change."},{"value":5,"label":"Pinnacle","description":"People follow because of who I am and what I represent — the influence is earned."}],"is_overlay":false,"overlay_type":null,"sort_order":21},{"id":"influence-2","pillar":"influence","sub_category":"Integrity Alignment","field_name":"integrityAlignment","question":"How closely do your daily actions align with your stated values?","description":"Integrity is not what you believe. It's the gap between what you say and what you do.","options":[{"value":1,"label":"Major disconnect","description":"If someone audited my calendar and bank statement, they'd see a different person than I claim to be."},{"value":2,"label":"Some gaps","description":"I believe the right things but my behavior doesn't always match."},{"value":3,"label":"Working on it","description":"I'm aware of the gaps and actively closing them."},{"value":4,"label":"Mostly aligned","description":"My actions reflect my values in most areas, with occasional slips."},{"value":5,"label":"Fully aligned","description":"My calendar, finances, and relationships would all confirm what I claim to value."}],"is_overlay":false,"overlay_type":null,"sort_order":22},{"id":"influence-3","pillar":"influence","sub_category":"Professional Credibility","field_name":"professionalCredibility","question":"How would peers and clients rate your professional reputation and expertise?","description":"This measures your credibility capital — the trust others place in your professional competence.","options":[{"value":1,"label":"Unknown or damaged","description":"My reputation needs serious repair or I haven't established one."},{"value":2,"label":"Emerging","description":"People know of me but I haven't built strong professional trust yet."},{"value":3,"label":"Respected","description":"I'm known as competent and reliable in my field."},{"value":4,"label":"Go-to expert","description":"People seek me out specifically because of my expertise and track record."},{"value":5,"label":"Industry authority","description":"My name carries weight in my profession. I'm a trusted reference point."}],"is_overlay":false,"overlay_type":null,"sort_order":23},{"id":"influence-4","pillar":"influence","sub_category":"Empathetic Listening","field_name":"empatheticListening","question":"How well do you listen to understand — not just to respond?","description":"Influence starts with understanding others. Empathetic listening is the foundation of all lasting influence.","options":[{"value":1,"label":"I talk more than I listen","description":"I'm usually waiting for my turn to speak."},{"value":2,"label":"Improving","description":"I try to listen but often catch myself formulating responses."},{"value":3,"label":"Active listener","description":"I can listen well when I focus, but I don't always focus."},{"value":4,"label":"Intentional","description":"I regularly seek to understand the other person's perspective before responding."},{"value":5,"label":"Master listener","description":"People feel genuinely heard when they talk to me. I listen to their values, not just their words."}],"is_overlay":false,"overlay_type":null,"sort_order":24},{"id":"influence-5","pillar":"influence","sub_category":"Gravitational Center","field_name":"gravitationalCenter","question":"Have you identified your core values — and does your daily life actually orbit around them?","description":"Your Gravitational Center (Tool #11) is the set of values you actually live by, not the ones you claim. Audit your calendar and bank statement — they don't lie.","options":[{"value":1,"label":"No idea","description":"If you asked me my top 5 values, I'd have to guess. My life doesn't reflect a clear center."},{"value":2,"label":"Vague sense","description":"I could name some values but my daily actions don't consistently reflect them."},{"value":3,"label":"Partially aligned","description":"I know my values and some of my life reflects them, but there are major gaps."},{"value":4,"label":"Strong alignment","description":"My core values are defined and most of my decisions filter through them."},{"value":5,"label":"Fully centered","description":"I've audited my calendar and finances against my values. My life orbits my gravitational center."}],"is_overlay":false,"overlay_type":null,"sort_order":25},{"id":"influence-6","pillar":"influence","sub_category":"Micro-Honesties","field_name":"microHonesties","question":"How vigilant are you about eliminating micro-dishonesties — the small lies, exaggerations, and omissions that erode trust?","description":"Influence dies in the small moments. The white lies, the inflated stories, the convenient omissions. Each one costs more trust than you think.","options":[{"value":1,"label":"Not aware","description":"I don't track the small stuff. I figure if the big things are honest, I'm fine."},{"value":2,"label":"Aware but frequent","description":"I know I exaggerate or omit things sometimes. It feels harmless but it adds up."},{"value":3,"label":"Catching them","description":"I've started noticing my micro-dishonesties and I'm working on reducing them."},{"value":4,"label":"Mostly clean","description":"I'm honest in the small moments most of the time. I correct myself when I slip."},{"value":5,"label":"Radically honest","description":"I've eliminated micro-dishonesties. People trust me because my small words and big words match."}],"is_overlay":false,"overlay_type":null,"sort_order":26},{"id":"influence-7","pillar":"influence","sub_category":"Word Management","field_name":"wordManagement","question":"How carefully do you manage your language — knowing that words shape expectations, commitments, and influence?","description":"The words you use create promises whether you intended them or not. 'I'll try' is not 'I will.' Word management is influence management.","options":[{"value":1,"label":"Careless with words","description":"I say things without thinking about the expectations I'm creating."},{"value":2,"label":"Sometimes sloppy","description":"I overcommit verbally and then struggle to deliver."},{"value":3,"label":"Improving","description":"I'm more careful with promises but I still create unintended expectations."},{"value":4,"label":"Precise language","description":"I choose my words deliberately. I under-promise and over-deliver consistently."},{"value":5,"label":"Words are architecture","description":"Every word I speak is intentional. My language builds trust, sets expectations, and increases influence."}],"is_overlay":false,"overlay_type":null,"sort_order":27},{"id":"influence-8","pillar":"influence","sub_category":"Personal Responsibility","field_name":"personalResponsibility","question":"When something goes wrong, how quickly do you look in the mirror instead of pointing at others?","description":"The mirror of influence: your ability to own outcomes — good and bad — determines whether people trust you with more responsibility.","options":[{"value":1,"label":"Blame first","description":"My first instinct is to identify who else is at fault."},{"value":2,"label":"Eventually own it","description":"I'll accept responsibility but usually after I've tried to deflect."},{"value":3,"label":"Mixed","description":"I take responsibility for things clearly in my control but struggle with gray areas."},{"value":4,"label":"Default to ownership","description":"My first move is to look at what I could have done differently."},{"value":5,"label":"Full ownership","description":"I own everything in my sphere. Even when others contribute to failure, I start with my role."}],"is_overlay":false,"overlay_type":null,"sort_order":28},{"id":"influence-9","pillar":"influence","sub_category":"Adaptive Influence","field_name":"adaptiveInfluence","question":"How effectively do you adapt your influence style to navigate different people's gravitational centers?","description":"Not everyone values what you value. Adaptive influence means understanding what drives someone else and connecting your message to their center.","options":[{"value":1,"label":"One style fits all","description":"I communicate the same way with everyone and wonder why some people don't respond."},{"value":2,"label":"Starting to adapt","description":"I've noticed different people need different approaches but I default to my own style."},{"value":3,"label":"Situationally aware","description":"I adjust my approach with close relationships but struggle with new or difficult people."},{"value":4,"label":"Consistently adaptive","description":"I read people's values and adjust my influence approach to connect with what matters to them."},{"value":5,"label":"Master navigator","description":"I can navigate any gravitational center. I influence by understanding first, speaking second."}],"is_overlay":false,"overlay_type":null,"sort_order":29},{"id":"influence-10","pillar":"influence","sub_category":"Influence Multiplier","field_name":"influenceMultiplier","question":"Do you understand that influence amplifies every other pillar — and are you building it deliberately?","description":"Influence is the multiplier across all pillars. Better influence = better time outcomes, stronger relationships, bigger numbers, and faster knowledge application.","options":[{"value":1,"label":"Never connected it","description":"I see influence as separate from my other goals, not as an amplifier."},{"value":2,"label":"Starting to see it","description":"I can see how influence helps but I'm not building it intentionally."},{"value":3,"label":"Partially leveraging","description":"I use my influence in some areas but miss opportunities to multiply across pillars."},{"value":4,"label":"Intentional multiplier","description":"I actively build influence knowing it will improve my time, people, numbers, and knowledge outcomes."},{"value":5,"label":"Full amplification","description":"My influence deliberately multiplies results across all five pillars. It's the engine of everything."}],"is_overlay":false,"overlay_type":null,"sort_order":30},{"id":"numbers-1","pillar":"numbers","sub_category":"Financial Awareness","field_name":"financialAwareness","question":"Right now, do you know your exact monthly income, expenses, and surplus or deficit?","description":"Not a guess. Not a hope. The actual numbers. Most people are running a business called their life without looking at the books.","options":[{"value":1,"label":"No idea","description":"I couldn't tell you within $1,000 what I spend monthly."},{"value":2,"label":"Rough estimate","description":"I know the ballpark but I'd be off by a meaningful amount."},{"value":3,"label":"Decent awareness","description":"I track my income and major expenses but miss the smaller leaks."},{"value":4,"label":"Solid tracking","description":"I know my numbers. I review them regularly."},{"value":5,"label":"Precision","description":"I know my real cost per hour, my surplus, and my three biggest financial leaks."}],"is_overlay":false,"overlay_type":null,"sort_order":31},{"id":"numbers-2","pillar":"numbers","sub_category":"Goal Specificity","field_name":"goalSpecificity","question":"How specific and measurable are your financial and life goals?","description":"'I want more money' is not a goal. 'I will increase my income by $2,000/month within 90 days' is.","options":[{"value":1,"label":"No goals set","description":"I'm just trying to get through the month."},{"value":2,"label":"Vague intentions","description":"I have ideas of what I want but nothing written or measurable."},{"value":3,"label":"Some specifics","description":"I have a few goals with numbers attached but no system to track them."},{"value":4,"label":"Clear targets","description":"My goals are specific, time-bound, and I review them regularly."},{"value":5,"label":"Engineered outcomes","description":"Every major goal has a number, a deadline, and a tracking system. I measure weekly."}],"is_overlay":false,"overlay_type":null,"sort_order":32},{"id":"numbers-3","pillar":"numbers","sub_category":"Investment Logic","field_name":"investmentLogic","question":"When you spend money — on tools, education, services, or opportunities — how logical is your investment process?","description":"This measures whether you evaluate cost vs. value before spending, or react emotionally.","options":[{"value":1,"label":"Emotional spender","description":"I buy when I feel like it and regret most of it later."},{"value":2,"label":"Impulsive but aware","description":"I know I shouldn't buy things impulsively, but I still do."},{"value":3,"label":"Sometimes calculated","description":"For big purchases I think it through. Small spending is still uncontrolled."},{"value":4,"label":"Consistently logical","description":"I evaluate ROI before most investments and track outcomes."},{"value":5,"label":"Strategic investor","description":"Every dollar I spend has a projected return. I track cost vs. value rigorously."}],"is_overlay":false,"overlay_type":null,"sort_order":33},{"id":"numbers-4","pillar":"numbers","sub_category":"Measurement Habit","field_name":"measurementHabit","question":"Do you regularly measure the results of your efforts — in money, time, or progress?","description":"What gets measured gets managed. What doesn't get measured gets neglected.","options":[{"value":1,"label":"Never","description":"I put in effort and hope for the best. I rarely look at the data."},{"value":2,"label":"Occasionally","description":"I check results when something feels off, but not systematically."},{"value":3,"label":"Monthly reviews","description":"I look at my numbers once a month but don't take action consistently."},{"value":4,"label":"Weekly tracking","description":"I review key metrics weekly and adjust course based on what I see."},{"value":5,"label":"Daily discipline","description":"I track what matters daily. Small improvements compound because I see them happening."}],"is_overlay":false,"overlay_type":null,"sort_order":34},{"id":"numbers-5","pillar":"numbers","sub_category":"Cost vs Value","field_name":"costVsValue","question":"Do you consistently evaluate decisions using the language of profitability — cost vs. value — instead of just looking at the price tag?","description":"A $500 course that produces $5,000 in results is not expensive. A $10 subscription you never use is. The gold roof fallacy: don't confuse cost with value.","options":[{"value":1,"label":"Price-driven","description":"I make most decisions based on the price tag, not the return."},{"value":2,"label":"Mostly price-driven","description":"I consider value sometimes but I default to 'can I afford it?' not 'will it produce?'"},{"value":3,"label":"Growing awareness","description":"I evaluate ROI on big decisions but small spending is still price-driven."},{"value":4,"label":"Value-first thinking","description":"Most of my spending decisions start with 'what will this produce?' not 'what does it cost?'"},{"value":5,"label":"Fluent in profitability","description":"I speak the language of profitability naturally. Every dollar is evaluated by its expected return."}],"is_overlay":false,"overlay_type":null,"sort_order":35},{"id":"numbers-6","pillar":"numbers","sub_category":"Number One Clarity","field_name":"numberOneClarity","question":"Do you have absolute clarity on your #1 priority — or are you spreading energy across too many 'priorities'?","description":"There is only one #1. The rocks and sand principle: if you don't put the big rocks in first, the sand fills the jar and the rocks never fit.","options":[{"value":1,"label":"No clear #1","description":"Everything feels important. I can't name one clear top priority."},{"value":2,"label":"Too many priorities","description":"I have 5+ 'priorities' which means I have none."},{"value":3,"label":"Roughly ranked","description":"I know what matters most but I still give too much energy to lesser things."},{"value":4,"label":"Clear #1","description":"I can name my #1 priority and most of my energy goes there."},{"value":5,"label":"Non-negotiable #1","description":"My #1 gets scheduled first. Everything else fits around it. Sand never displaces rocks."}],"is_overlay":false,"overlay_type":null,"sort_order":36},{"id":"numbers-7","pillar":"numbers","sub_category":"Small Improvements","field_name":"smallImprovements","question":"Do you practice the power of compounding small improvements — getting 1% better consistently?","description":"1% improvement daily = 37× improvement in a year. Small improvements compound into massive results. Most people chase big wins and miss the math.","options":[{"value":1,"label":"Big wins only","description":"I wait for breakthrough moments and ignore small daily gains."},{"value":2,"label":"Inconsistent","description":"I make small improvements sometimes but I don't sustain them."},{"value":3,"label":"Developing the habit","description":"I'm working on daily improvement but I miss more days than I hit."},{"value":4,"label":"Consistent improver","description":"I make small, measurable improvements in key areas most weeks."},{"value":5,"label":"Compounding machine","description":"I track and make daily improvements. I trust the compound curve and I'm living it."}],"is_overlay":false,"overlay_type":null,"sort_order":37},{"id":"numbers-8","pillar":"numbers","sub_category":"Negative Math","field_name":"negativeMath","question":"Do you understand the surprising power of cutting losses — that removing a -5 is the same as adding a +5?","description":"Negative math: most people only think about adding. But eliminating costs, bad habits, or draining relationships has the same numerical impact as gains.","options":[{"value":1,"label":"Only add","description":"I focus entirely on making more and never think about cutting losses."},{"value":2,"label":"Reluctant cutter","description":"I know I should cut losses but I hold on too long — sunk cost fallacy wins."},{"value":3,"label":"Starting to cut","description":"I've cut some losses but I still resist letting go of things that aren't working."},{"value":4,"label":"Active loss cutter","description":"I regularly evaluate what to eliminate. I understand that subtraction is addition."},{"value":5,"label":"Master of negative math","description":"I cut losses fast and early. I know that removing a -5 gives me the same result as finding a +5."}],"is_overlay":false,"overlay_type":null,"sort_order":38},{"id":"numbers-9","pillar":"numbers","sub_category":"Income Multiplier","field_name":"incomeMultiplier","question":"Have you mapped out how compound improvements over 90 days could multiply your income?","description":"The Income Multiplier Model (Tool #12) shows how small improvements across pillars create exponential income growth over 90 days, not linear.","options":[{"value":1,"label":"No model","description":"I have no plan for how to systematically increase my income."},{"value":2,"label":"Vague goal","description":"I want to make more money but I don't have a compound improvement plan."},{"value":3,"label":"Some planning","description":"I've identified a few improvements but I haven't modeled the compound effect."},{"value":4,"label":"90-day model","description":"I have a clear plan for compound improvements and I'm executing on it."},{"value":5,"label":"Fully modeled","description":"I've built and am running a compound improvement model. I can project my income growth mathematically."}],"is_overlay":false,"overlay_type":null,"sort_order":39},{"id":"numbers-10","pillar":"numbers","sub_category":"Negotiation Skill","field_name":"negotiationSkill","question":"How effectively do you negotiate — reframing scope, offering alternatives, and leveraging the five currencies of value?","description":"Negotiation is the skill that protects all your other numbers. The five currencies: money, time, expertise, access, and relationships. Most people only negotiate with one.","options":[{"value":1,"label":"Avoid negotiation","description":"I accept what's offered. Negotiation feels uncomfortable and I avoid it."},{"value":2,"label":"Basic haggling","description":"I negotiate on price sometimes but I don't think about the other currencies."},{"value":3,"label":"Developing skill","description":"I negotiate more often and I'm starting to think beyond just money."},{"value":4,"label":"Multi-currency negotiator","description":"I negotiate using multiple currencies — time, expertise, access — not just money."},{"value":5,"label":"Master negotiator","description":"I reframe scope, leverage all five currencies, and consistently create more value in every deal."}],"is_overlay":false,"overlay_type":null,"sort_order":40},{"id":"knowledge-1","pillar":"knowledge","sub_category":"Learning Hours","field_name":"learningHours","question":"How many hours per week do you invest in intentional learning — not passive consumption?","description":"Watching YouTube isn't learning. Reading a book without application isn't learning. This is about deliberate skill and knowledge acquisition.","options":[{"value":1,"label":"Zero hours","description":"I haven't intentionally learned anything new in months."},{"value":2,"label":"1-2 hours","description":"I read or listen to something occasionally but it's not structured."},{"value":3,"label":"3-5 hours","description":"I make time for learning but it's inconsistent."},{"value":4,"label":"5-8 hours","description":"I have a regular learning routine with specific topics and goals."},{"value":5,"label":"8+ hours","description":"Learning is scheduled, tracked, and directly tied to my goals."}],"is_overlay":false,"overlay_type":null,"sort_order":41},{"id":"knowledge-2","pillar":"knowledge","sub_category":"Application Rate","field_name":"applicationRate","question":"Of everything you've learned in the last 90 days, how much have you actually applied?","description":"Knowledge without application is entertainment. This measures whether your learning converts to action.","options":[{"value":1,"label":"Almost nothing","description":"I consume information but rarely change my behavior because of it."},{"value":2,"label":"Maybe 10%","description":"I've applied a few things but most knowledge sits unused."},{"value":3,"label":"About 30%","description":"I apply some of what I learn, especially when it's immediately relevant."},{"value":4,"label":"About 50%","description":"I actively look for ways to implement what I'm learning."},{"value":5,"label":"70%+","description":"I learn with the specific intent to apply. Every course, book, or lesson gets tested."}],"is_overlay":false,"overlay_type":null,"sort_order":42},{"id":"knowledge-3","pillar":"knowledge","sub_category":"Bias Awareness","field_name":"biasAwareness","question":"How aware are you of the biases that distort your thinking and decisions?","description":"Confirmation bias, sunk cost fallacy, Dunning-Kruger — these invisible forces shape your choices. Do you see them?","options":[{"value":1,"label":"Unaware","description":"I trust my gut and don't question my assumptions."},{"value":2,"label":"Heard of them","description":"I know biases exist but don't actively check for them in my own thinking."},{"value":3,"label":"Developing awareness","description":"I catch myself sometimes but biases still slip through."},{"value":4,"label":"Active questioning","description":"I regularly challenge my assumptions and seek contrary evidence."},{"value":5,"label":"Systematic checks","description":"I have a process for testing my decisions against common biases before I commit."}],"is_overlay":false,"overlay_type":null,"sort_order":43},{"id":"knowledge-4","pillar":"knowledge","sub_category":"Highest & Best Use","field_name":"highestBestUse","question":"Is your current knowledge being applied at its highest and best use?","description":"A real estate term repurposed: are you deploying what you know in the way that produces the maximum return?","options":[{"value":1,"label":"Completely misaligned","description":"What I know and what I do are barely connected."},{"value":2,"label":"Underutilized","description":"I have skills and knowledge that aren't being used."},{"value":3,"label":"Partially aligned","description":"Some of my work uses my best knowledge, but there's significant waste."},{"value":4,"label":"Mostly optimized","description":"I'm applying most of my expertise where it matters most."},{"value":5,"label":"Fully deployed","description":"My knowledge is being used at its maximum potential in every major area."}],"is_overlay":false,"overlay_type":null,"sort_order":44},{"id":"knowledge-5","pillar":"knowledge","sub_category":"Supply & Demand","field_name":"supplyAndDemand","question":"Do you understand how supply and demand applies to your skills — and are you building scarcity into your unique design?","description":"When everyone can do what you do, your value drops. Your unique design — the combination of skills, experience, and perspective only you have — is your scarcity advantage.","options":[{"value":1,"label":"Commodity skills","description":"I do what thousands of others can do. There's nothing scarce about my offering."},{"value":2,"label":"Some awareness","description":"I know I need to differentiate but I haven't figured out my unique combination."},{"value":3,"label":"Developing uniqueness","description":"I can identify some things I do differently but I haven't fully leveraged them."},{"value":4,"label":"Scarce combination","description":"I've identified my unique skill combination and I'm building my reputation around it."},{"value":5,"label":"Irreplaceable design","description":"My unique design creates genuine scarcity. People seek me out for what only I can deliver."}],"is_overlay":false,"overlay_type":null,"sort_order":45},{"id":"knowledge-6","pillar":"knowledge","sub_category":"Substitution Risk","field_name":"substitutionRisk","question":"How easily could you be replaced — by a person, a process, or a technology?","description":"Stand apart or get replaced. If someone could do your job for less, if AI could automate your tasks, your value is at risk. What makes you non-substitutable?","options":[{"value":1,"label":"Easily replaced","description":"Someone else could do what I do with minimal training."},{"value":2,"label":"Somewhat replaceable","description":"It would take some effort but I'm not hard to replace."},{"value":3,"label":"Moderately protected","description":"I have some specialized skills that make replacement harder, but not impossible."},{"value":4,"label":"Hard to replace","description":"My combination of skills, relationships, and knowledge would be very difficult to substitute."},{"value":5,"label":"Non-substitutable","description":"What I bring is a combination that cannot be replicated by a person, process, or technology."}],"is_overlay":false,"overlay_type":null,"sort_order":46},{"id":"knowledge-7","pillar":"knowledge","sub_category":"Double Jeopardy","field_name":"doubleJeopardy","question":"How well do you apply the Rule of Double Jeopardy — never paying for the same mistake twice?","description":"Every mistake is tuition. But paying twice for the same lesson is waste. Do you have a system for extracting and applying the lesson the first time?","options":[{"value":1,"label":"Repeat offender","description":"I make the same mistakes over and over. I don't extract lessons."},{"value":2,"label":"Slow learner","description":"I eventually learn but it usually takes multiple painful repetitions."},{"value":3,"label":"Improving","description":"I catch repeat patterns faster now but I still pay double sometimes."},{"value":4,"label":"One-lesson learner","description":"I have a system for capturing lessons and I rarely make the same mistake twice."},{"value":5,"label":"Zero double jeopardy","description":"Every mistake produces a documented lesson. I extract the value the first time and never pay again."}],"is_overlay":false,"overlay_type":null,"sort_order":47},{"id":"knowledge-8","pillar":"knowledge","sub_category":"Knowledge Compounding","field_name":"knowledgeCompounding","question":"Do you see how knowledge compounds across pillars — or do you treat learning as siloed information?","description":"The best knowledge multiplies. What you learn about people improves your influence. What you learn about numbers improves your time decisions. Compounding is cross-pillar.","options":[{"value":1,"label":"Completely siloed","description":"I learn things but they stay in their category. I don't connect across domains."},{"value":2,"label":"Occasionally connected","description":"Sometimes I see connections between areas but I don't pursue them."},{"value":3,"label":"Starting to compound","description":"I'm beginning to apply lessons from one area to improve another."},{"value":4,"label":"Active compounder","description":"I deliberately look for cross-pillar applications of everything I learn."},{"value":5,"label":"Full compounding","description":"Every piece of knowledge I acquire gets tested for application across all five pillars."}],"is_overlay":false,"overlay_type":null,"sort_order":48},{"id":"knowledge-9","pillar":"knowledge","sub_category":"Weighted Analysis","field_name":"weightedAnalysis","question":"How well do you practice the art of true consideration — weighing decisions with all relevant factors, not just the obvious ones?","description":"Weighted analysis means assigning appropriate importance to each factor in a decision, not just going with the loudest signal or first impression.","options":[{"value":1,"label":"Gut decisions","description":"I go with my first instinct on almost everything."},{"value":2,"label":"Some analysis","description":"I think about big decisions but I miss important factors regularly."},{"value":3,"label":"Developing rigor","description":"I try to weigh multiple factors but I still over-index on one or two."},{"value":4,"label":"Disciplined analysis","description":"I systematically consider multiple factors and weight them by importance before deciding."},{"value":5,"label":"Master analyst","description":"I use weighted analysis as a default. Every major decision gets a structured evaluation."}],"is_overlay":false,"overlay_type":null,"sort_order":49},{"id":"knowledge-10","pillar":"knowledge","sub_category":"Perception vs Perspective","field_name":"perceptionVsPerspective","question":"Do you understand the distance between perception and perspective — between where you stand and where you truly see?","description":"Perception is what you see from where you stand. Perspective is the ability to see from where others stand. The gap between them determines the quality of your decisions.","options":[{"value":1,"label":"Locked in perception","description":"I see things from my position and assume that's the full picture."},{"value":2,"label":"Aware of the gap","description":"I know my view is limited but I struggle to see from other angles."},{"value":3,"label":"Developing perspective","description":"I can take other viewpoints when prompted but it's not automatic."},{"value":4,"label":"Multi-perspective","description":"I regularly step outside my own view to evaluate situations from multiple angles."},{"value":5,"label":"Full perspective","description":"I naturally integrate multiple viewpoints. I know that where I stand is not all there is to see."}],"is_overlay":false,"overlay_type":null,"sort_order":50},{"id":"rel-1","pillar":"relationship","sub_category":"communicationSafety","field_name":"communicationSafety","question":"How safe do you feel bringing up difficult topics with your partner?","description":"Real communication requires safety. If you can't say the hard thing, the hard thing festers.","options":[{"value":1,"label":"Not safe at all","description":"I avoid hard topics entirely — they always end in a fight or shutdown."},{"value":2,"label":"Rarely safe","description":"I can bring things up, but it usually goes sideways."},{"value":3,"label":"Sometimes safe","description":"Depends on the topic and the timing. It's hit or miss."},{"value":4,"label":"Mostly safe","description":"We can talk about most things, even when it's uncomfortable."},{"value":5,"label":"Completely safe","description":"I trust that we can address anything with respect and honesty."}],"is_overlay":true,"overlay_type":"relationship","sort_order":51},{"id":"rel-2","pillar":"relationship","sub_category":"conflictResolution","field_name":"conflictResolution","question":"When you and your partner disagree, how constructively is it resolved?","description":"Conflict isn't the enemy. Unresolved conflict is.","options":[{"value":1,"label":"Destructive","description":"Arguments escalate. Someone shuts down or blows up every time."},{"value":2,"label":"Mostly unproductive","description":"We argue but rarely reach resolution. Issues pile up."},{"value":3,"label":"Mixed results","description":"Some conflicts get resolved, others get swept under the rug."},{"value":4,"label":"Usually constructive","description":"We work through most disagreements and find common ground."},{"value":5,"label":"Healthy resolution","description":"We address issues directly, listen fully, and grow from disagreements."}],"is_overlay":true,"overlay_type":"relationship","sort_order":52},{"id":"rel-3","pillar":"relationship","sub_category":"sharedVision","field_name":"sharedVision","question":"How aligned are you and your partner on your 5-year vision for life together?","description":"A relationship without shared direction is two people heading to different destinations in the same car.","options":[{"value":1,"label":"Completely misaligned","description":"We want fundamentally different things and haven't addressed it."},{"value":2,"label":"Vaguely aware","description":"We have different ideas about the future but don't discuss it much."},{"value":3,"label":"Partially aligned","description":"We agree on some big things but haven't mapped out a shared vision."},{"value":4,"label":"Mostly aligned","description":"We've talked about it and agree on the major goals."},{"value":5,"label":"Fully aligned","description":"We have a clear, shared vision and actively plan toward it together."}],"is_overlay":true,"overlay_type":"relationship","sort_order":53},{"id":"rel-4","pillar":"relationship","sub_category":"emotionalDeposits","field_name":"emotionalDeposits","question":"How consistently do you make emotional deposits into your partner's 'Love Bank'?","description":"From Harley's Love Bank: every interaction is a deposit or withdrawal. The balance determines the health of the relationship.","options":[{"value":1,"label":"Mostly withdrawals","description":"I'm running a deficit. I take more than I give emotionally."},{"value":2,"label":"Inconsistent","description":"I make deposits sometimes but I'm not intentional about it."},{"value":3,"label":"Balanced","description":"I try to give as much as I take, but I could be more intentional."},{"value":4,"label":"Regular deposits","description":"I actively look for ways to make my partner feel valued and appreciated."},{"value":5,"label":"Overflowing","description":"I consistently and intentionally invest in my partner's emotional well-being."}],"is_overlay":true,"overlay_type":"relationship","sort_order":54},{"id":"rel-5","pillar":"relationship","sub_category":"trustFoundation","field_name":"trustFoundation","question":"How much do you trust your partner with your vulnerabilities and fears?","description":"Trust is built in drops and lost in buckets. This measures the depth of your relational foundation.","options":[{"value":1,"label":"No trust","description":"I don't feel safe being vulnerable. I keep my guard up."},{"value":2,"label":"Limited trust","description":"I share some things but hold back the really important stuff."},{"value":3,"label":"Moderate trust","description":"I trust my partner with most things but there are areas I protect."},{"value":4,"label":"Strong trust","description":"I can be vulnerable about almost anything without fear of judgment."},{"value":5,"label":"Complete trust","description":"I trust this person with my deepest fears and biggest dreams."}],"is_overlay":true,"overlay_type":"relationship","sort_order":55},{"id":"rel-6","pillar":"relationship","sub_category":"financialAlignment","field_name":"financialAlignment","question":"How aligned are you and your partner on spending, saving, and financial goals?","description":"Money is the #1 topic couples fight about. This isn't about how much you have — it's about whether you agree on how to handle it.","options":[{"value":1,"label":"Major conflict","description":"Money is a constant source of tension. We have completely different philosophies."},{"value":2,"label":"Frequent disagreement","description":"We fight about money regularly and don't have shared financial goals."},{"value":3,"label":"Some alignment","description":"We agree on the basics but haven't built a real financial plan together."},{"value":4,"label":"Mostly aligned","description":"We have shared goals and mostly agree on spending and saving priorities."},{"value":5,"label":"Fully aligned","description":"We budget together, share financial goals, and make decisions as a team."}],"is_overlay":true,"overlay_type":"relationship","sort_order":56},{"id":"rel-7","pillar":"relationship","sub_category":"boundaryRespect","field_name":"boundaryRespect","question":"How well does your partner respect your personal boundaries?","description":"Boundaries aren't walls — they're doors with locks. Respecting them is respecting the person.","options":[{"value":1,"label":"No respect","description":"My boundaries are consistently crossed or dismissed."},{"value":2,"label":"Sometimes","description":"Some boundaries are respected, others are ignored or tested."},{"value":3,"label":"Usually","description":"Most of my boundaries are respected, but some get pushed."},{"value":4,"label":"Consistently","description":"My partner actively respects my boundaries even when they don't fully understand them."},{"value":5,"label":"Absolutely","description":"My boundaries are honored without question and my partner sets healthy ones too."}],"is_overlay":true,"overlay_type":"relationship","sort_order":57},{"id":"rel-8","pillar":"relationship","sub_category":"qualityTime","field_name":"qualityTime","question":"How intentional is the quality time you spend together each week?","description":"Being in the same room is not quality time. This measures intentional, undistracted connection.","options":[{"value":1,"label":"Almost none","description":"We rarely spend intentional time together. We're roommates."},{"value":2,"label":"Occasional","description":"We do things together sometimes but it's rarely intentional or focused."},{"value":3,"label":"Moderate","description":"We try to spend time together weekly but life often gets in the way."},{"value":4,"label":"Regular","description":"We have consistent rituals — date nights, walks, check-ins."},{"value":5,"label":"Deeply intentional","description":"We prioritize focused, undistracted connection time every week without fail."}],"is_overlay":true,"overlay_type":"relationship","sort_order":58},{"id":"rel-9","pillar":"relationship","sub_category":"roleClarity","field_name":"roleClarity","question":"How clearly defined are roles and responsibilities in your household?","description":"Unclear roles breed resentment. Clarity breeds partnership.","options":[{"value":1,"label":"Constant friction","description":"Nobody knows who does what. Everything becomes a negotiation or fight."},{"value":2,"label":"Unclear","description":"Roles fall on whoever notices first, which leads to resentment."},{"value":3,"label":"Somewhat clear","description":"We have some unspoken agreements but they're not well defined."},{"value":4,"label":"Well defined","description":"We've discussed and divided responsibilities fairly."},{"value":5,"label":"Excellent system","description":"We have clear, agreed-upon roles that play to each person's strengths."}],"is_overlay":true,"overlay_type":"relationship","sort_order":59},{"id":"rel-10","pillar":"relationship","sub_category":"growthSupport","field_name":"growthSupport","question":"How actively does your partner support your personal growth and goals?","description":"A great partner doesn't just tolerate your dreams — they water them.","options":[{"value":1,"label":"Actively discourages","description":"My partner feels threatened by my growth or undermines my goals."},{"value":2,"label":"Indifferent","description":"My partner doesn't oppose my growth but doesn't actively support it either."},{"value":3,"label":"Somewhat supportive","description":"They encourage me verbally but don't make space for it."},{"value":4,"label":"Actively supportive","description":"My partner makes sacrifices and adjustments to help me grow."},{"value":5,"label":"Champion","description":"My partner is my biggest advocate and actively invests in my development."}],"is_overlay":true,"overlay_type":"relationship","sort_order":60},{"id":"rel-11","pillar":"relationship","sub_category":"intimacyConnection","field_name":"intimacyConnection","question":"How satisfied are you with the emotional and physical intimacy in your relationship?","description":"Intimacy is the glue. Without it, everything else slowly comes apart.","options":[{"value":1,"label":"Very dissatisfied","description":"There's a significant disconnect both emotionally and physically."},{"value":2,"label":"Dissatisfied","description":"One or both areas are lacking and it's affecting the relationship."},{"value":3,"label":"Mixed","description":"Some areas are fine but others need work."},{"value":4,"label":"Satisfied","description":"We're connected in most ways and actively nurture our intimacy."},{"value":5,"label":"Deeply satisfied","description":"Our emotional and physical connection is strong, intentional, and growing."}],"is_overlay":true,"overlay_type":"relationship","sort_order":61},{"id":"rel-12","pillar":"relationship","sub_category":"forgivenessCapacity","field_name":"forgivenessCapacity","question":"How quickly and genuinely can you and your partner forgive after conflict?","description":"Unforgiveness is a poison you drink hoping the other person gets sick.","options":[{"value":1,"label":"We hold grudges","description":"Past offenses get stockpiled and weaponized in future arguments."},{"value":2,"label":"Slow to forgive","description":"It takes a long time and a lot of effort to move past hurt."},{"value":3,"label":"Eventually","description":"We forgive but it takes time and sometimes the wound reopens."},{"value":4,"label":"Usually quick","description":"We can address hurt, apologize genuinely, and move forward."},{"value":5,"label":"Gracious and fast","description":"We extend grace quickly because we value the relationship over being right."}],"is_overlay":true,"overlay_type":"relationship","sort_order":62},{"id":"rel-13","pillar":"relationship","sub_category":"appreciationFrequency","field_name":"appreciationFrequency","question":"How often do you express genuine appreciation for your partner?","description":"Appreciation is the cheapest, most effective deposit you can make. How often are you making it?","options":[{"value":1,"label":"Rarely","description":"I can't remember the last time I expressed genuine appreciation."},{"value":2,"label":"Occasionally","description":"I say thank you sometimes but it's not a habit."},{"value":3,"label":"Sometimes","description":"I express it when something big happens but not for the everyday things."},{"value":4,"label":"Frequently","description":"I make a point to express gratitude multiple times a week."},{"value":5,"label":"Daily habit","description":"I express specific, genuine appreciation every single day."}],"is_overlay":true,"overlay_type":"relationship","sort_order":63},{"id":"rel-14","pillar":"relationship","sub_category":"decisionPartnership","field_name":"decisionPartnership","question":"How well do you and your partner make major decisions together as a team?","description":"Unilateral decisions erode partnership. Shared decisions build it.","options":[{"value":1,"label":"One person decides","description":"One partner makes all the big calls and the other goes along or resents it."},{"value":2,"label":"Frequent conflict","description":"We try to decide together but it usually ends in argument."},{"value":3,"label":"Mixed","description":"Some decisions are shared, others are made unilaterally."},{"value":4,"label":"Strong partnership","description":"We discuss major decisions together and usually find alignment."},{"value":5,"label":"True team","description":"Every major decision is made as a partnership with mutual respect."}],"is_overlay":true,"overlay_type":"relationship","sort_order":64},{"id":"rel-15","pillar":"relationship","sub_category":"externalPressure","field_name":"externalPressure","question":"How well does your relationship handle external stress — family, work, finances?","description":"External pressure doesn't create cracks. It reveals them.","options":[{"value":1,"label":"It breaks us","description":"External stress causes major fights and pulls us apart."},{"value":2,"label":"Significant strain","description":"We struggle under pressure and often take it out on each other."},{"value":3,"label":"We survive","description":"We get through tough times but it takes a toll on the relationship."},{"value":4,"label":"We cope well","description":"We lean on each other during hard times and usually come out stronger."},{"value":5,"label":"It strengthens us","description":"External pressure brings us closer. We face challenges as a united front."}],"is_overlay":true,"overlay_type":"relationship","sort_order":65},{"id":"lead-1","pillar":"leadership","sub_category":"visionClarity","field_name":"visionClarity","question":"How clearly can every team member articulate the organization's vision and their role in it?","description":"If your people can't explain the mission in one sentence, they can't execute it.","options":[{"value":1,"label":"No shared vision","description":"People couldn't tell you the mission if you asked."},{"value":2,"label":"Vaguely understood","description":"There's a mission statement somewhere, but nobody lives by it."},{"value":3,"label":"Leadership knows it","description":"Leaders can articulate it but the team hasn't internalized it."},{"value":4,"label":"Mostly aligned","description":"Most team members understand the vision and see their role in it."},{"value":5,"label":"Crystal clear","description":"Everyone can articulate the vision and connects their daily work to it."}],"is_overlay":true,"overlay_type":"leadership","sort_order":66},{"id":"lead-2","pillar":"leadership","sub_category":"delegationEffectiveness","field_name":"delegationEffectiveness","question":"How effectively does leadership delegate tasks matched to people's strengths?","description":"Delegation is not dumping work. It's matching talent to task.","options":[{"value":1,"label":"No delegation","description":"Leaders try to do everything themselves. Bottleneck city."},{"value":2,"label":"Poor delegation","description":"Tasks get assigned randomly without regard for strengths."},{"value":3,"label":"Basic","description":"Some delegation happens but it's not strategic or strength-based."},{"value":4,"label":"Effective","description":"Leaders delegate intentionally and match tasks to team strengths."},{"value":5,"label":"Masterful","description":"Everyone works in their zone of genius. Delegation multiplies output."}],"is_overlay":true,"overlay_type":"leadership","sort_order":67},{"id":"lead-3","pillar":"leadership","sub_category":"accountabilityCulture","field_name":"accountabilityCulture","question":"How consistently are team members held accountable for commitments?","description":"Accountability without relationship is dictatorship. Relationship without accountability is indulgence.","options":[{"value":1,"label":"No accountability","description":"People miss deadlines and nobody says anything."},{"value":2,"label":"Inconsistent","description":"Some people are held accountable, others aren't. It breeds resentment."},{"value":3,"label":"Moderate","description":"There are systems but they're not enforced consistently."},{"value":4,"label":"Strong","description":"Commitments are tracked and people are held accountable fairly."},{"value":5,"label":"Culture of ownership","description":"Team members hold themselves and each other accountable proactively."}],"is_overlay":true,"overlay_type":"leadership","sort_order":68},{"id":"lead-4","pillar":"leadership","sub_category":"decisionSpeed","field_name":"decisionSpeed","question":"How quickly can your team make and execute important decisions?","description":"A good plan executed today beats a perfect plan executed next month.","options":[{"value":1,"label":"Paralyzed","description":"Decisions take forever. Analysis paralysis is the default."},{"value":2,"label":"Very slow","description":"Everything requires multiple meetings and layers of approval."},{"value":3,"label":"Average","description":"Some decisions move quickly, others get stuck in process."},{"value":4,"label":"Fast","description":"Decision-making is efficient with clear authority and process."},{"value":5,"label":"Decisive","description":"We decide quickly, execute immediately, and adjust as we learn."}],"is_overlay":true,"overlay_type":"leadership","sort_order":69},{"id":"lead-5","pillar":"leadership","sub_category":"teamTrust","field_name":"teamTrust","question":"How much psychological safety exists for team members to speak honestly?","description":"If people can't tell you the truth, they'll tell you what you want to hear — and you'll make bad decisions.","options":[{"value":1,"label":"Fear-based","description":"People are afraid to speak up. Disagreement is punished."},{"value":2,"label":"Cautious","description":"People filter heavily. They share good news fast and bad news slow."},{"value":3,"label":"Moderate safety","description":"Some people feel safe speaking up, others don't."},{"value":4,"label":"High safety","description":"Most team members feel comfortable sharing honest feedback."},{"value":5,"label":"Full trust","description":"Everyone speaks freely. Dissent is welcomed and encouraged."}],"is_overlay":true,"overlay_type":"leadership","sort_order":70},{"id":"lead-6","pillar":"leadership","sub_category":"conflictManagement","field_name":"conflictManagement","question":"How constructively does your team handle disagreements?","description":"Teams that can't fight well together can't build well together.","options":[{"value":1,"label":"Toxic","description":"Conflict turns personal. People attack, avoid, or gossip."},{"value":2,"label":"Dysfunctional","description":"Disagreements are poorly handled and leave lasting damage."},{"value":3,"label":"Mixed","description":"Some conflicts are handled well, others escalate unnecessarily."},{"value":4,"label":"Constructive","description":"We address disagreements directly and work toward resolution."},{"value":5,"label":"Excellent","description":"Conflict is viewed as productive tension that makes us better."}],"is_overlay":true,"overlay_type":"leadership","sort_order":71},{"id":"lead-7","pillar":"leadership","sub_category":"talentDevelopment","field_name":"talentDevelopment","question":"How actively does leadership invest in growing team members' skills?","description":"If you're not growing your people, your competition is recruiting them.","options":[{"value":1,"label":"No investment","description":"There's no budget, time, or attention given to development."},{"value":2,"label":"Minimal","description":"Occasional training but no real development strategy."},{"value":3,"label":"Some effort","description":"There are some programs but they're not personalized or prioritized."},{"value":4,"label":"Active investment","description":"Leadership has development plans and allocates resources for growth."},{"value":5,"label":"Culture of growth","description":"Development is built into the DNA. Everyone has a growth path."}],"is_overlay":true,"overlay_type":"leadership","sort_order":72},{"id":"lead-8","pillar":"leadership","sub_category":"communicationFlow","field_name":"communicationFlow","question":"How effectively does information flow between leadership and the team?","description":"Information hoarding is power hoarding. Healthy organizations share context freely.","options":[{"value":1,"label":"Siloed","description":"Information is hoarded. Teams don't know what other teams are doing."},{"value":2,"label":"Top-down only","description":"Leaders push information down but rarely listen to feedback."},{"value":3,"label":"Adequate","description":"Most important information flows but there are gaps and delays."},{"value":4,"label":"Strong","description":"Communication is transparent and flows in both directions."},{"value":5,"label":"Excellent","description":"Information moves freely. Everyone has the context they need to act."}],"is_overlay":true,"overlay_type":"leadership","sort_order":73},{"id":"lead-9","pillar":"leadership","sub_category":"innovationCapacity","field_name":"innovationCapacity","question":"How encouraged and supported is creative thinking and new ideas?","description":"Innovation dies the moment 'we've always done it this way' becomes acceptable.","options":[{"value":1,"label":"Shut down","description":"New ideas are rejected or ignored. Status quo is king."},{"value":2,"label":"Discouraged","description":"People have ideas but learn not to share them."},{"value":3,"label":"Sometimes","description":"Innovation is welcomed in some areas but not others."},{"value":4,"label":"Encouraged","description":"Leadership actively solicits new ideas and supports experimentation."},{"value":5,"label":"Thriving","description":"Innovation is expected. Failure is treated as learning. Ideas are celebrated."}],"is_overlay":true,"overlay_type":"leadership","sort_order":74},{"id":"lead-10","pillar":"leadership","sub_category":"changeReadiness","field_name":"changeReadiness","question":"How quickly can your team adapt when priorities or conditions shift?","description":"The speed of your adaptation is the speed of your survival.","options":[{"value":1,"label":"Rigid","description":"Change is resisted at every level. We're stuck in our ways."},{"value":2,"label":"Slow","description":"We eventually adapt but it takes a long time and a lot of pain."},{"value":3,"label":"Moderate","description":"We can adapt but it's uncomfortable and creates friction."},{"value":4,"label":"Agile","description":"We adapt quickly and use change as an opportunity."},{"value":5,"label":"Thrives on change","description":"The team is built for change. We pivot fast and stay aligned."}],"is_overlay":true,"overlay_type":"leadership","sort_order":75},{"id":"lead-11","pillar":"leadership","sub_category":"meetingEffectiveness","field_name":"meetingEffectiveness","question":"How productive and focused are your team meetings?","description":"Bad meetings are where good hours go to die.","options":[{"value":1,"label":"Total waste","description":"Meetings are unfocused, too long, and accomplish nothing."},{"value":2,"label":"Mostly unproductive","description":"Some value but too many meetings that could have been emails."},{"value":3,"label":"Mixed","description":"Some meetings are productive, others are time sinks."},{"value":4,"label":"Productive","description":"Meetings have agendas, outcomes, and respect everyone's time."},{"value":5,"label":"Highly efficient","description":"Every meeting has a clear purpose, ends on time, and drives action."}],"is_overlay":true,"overlay_type":"leadership","sort_order":76},{"id":"lead-12","pillar":"leadership","sub_category":"feedbackCulture","field_name":"feedbackCulture","question":"How regularly and constructively is feedback given and received?","description":"Feedback is a gift. But most organizations wrap it in sandpaper.","options":[{"value":1,"label":"No feedback","description":"People don't give or receive feedback. Ever."},{"value":2,"label":"Only negative","description":"Feedback only happens when something goes wrong."},{"value":3,"label":"Infrequent","description":"Annual reviews exist but real-time feedback is rare."},{"value":4,"label":"Regular","description":"Feedback is given frequently and received constructively."},{"value":5,"label":"Continuous","description":"Feedback is woven into daily interactions. It's expected and welcomed."}],"is_overlay":true,"overlay_type":"leadership","sort_order":77},{"id":"lead-13","pillar":"leadership","sub_category":"strategicThinking","field_name":"strategicThinking","question":"How well does your team distinguish urgent tasks from strategic priorities?","description":"If everything is urgent, nothing is strategic. Covey's Quadrant 2 at the organizational level.","options":[{"value":1,"label":"All reactive","description":"We're constantly putting out fires. No time for strategy."},{"value":2,"label":"Mostly reactive","description":"Strategic work gets planned but urgent tasks always take over."},{"value":3,"label":"Balanced effort","description":"We try to balance urgent and strategic but it's a constant struggle."},{"value":4,"label":"Strategy-led","description":"Strategic priorities are protected and urgent tasks are managed."},{"value":5,"label":"Visionary","description":"We invest heavily in Quadrant 2 work and prevent most fires before they start."}],"is_overlay":true,"overlay_type":"leadership","sort_order":78},{"id":"lead-14","pillar":"leadership","sub_category":"resourceAllocation","field_name":"resourceAllocation","question":"How efficiently are time, money, and people allocated to highest-value work?","description":"Resource allocation is leadership's signature. Where you put your resources reveals your real priorities.","options":[{"value":1,"label":"Misallocated","description":"Resources go to the loudest voice, not the highest value."},{"value":2,"label":"Inefficient","description":"There's waste and duplication. Nobody tracks ROI on resource allocation."},{"value":3,"label":"Adequate","description":"Resources are mostly allocated well but there's room for improvement."},{"value":4,"label":"Efficient","description":"We track and optimize resource allocation against our strategic priorities."},{"value":5,"label":"Maximized","description":"Every dollar, hour, and person is deployed at their highest and best use."}],"is_overlay":true,"overlay_type":"leadership","sort_order":79},{"id":"lead-15","pillar":"leadership","sub_category":"cultureHealth","field_name":"cultureHealth","question":"How aligned is the team's daily behavior with the organization's stated values?","description":"Culture is not what you say. It's what you tolerate.","options":[{"value":1,"label":"Total disconnect","description":"Values are on the wall but nowhere in the hallway."},{"value":2,"label":"Significant gap","description":"Leadership talks values but daily behavior doesn't match."},{"value":3,"label":"Partial alignment","description":"Some values are lived, others are aspirational at best."},{"value":4,"label":"Mostly aligned","description":"Daily behavior generally reflects stated values with occasional gaps."},{"value":5,"label":"Fully embodied","description":"Values are lived daily. People call out misalignment. Culture is real."}],"is_overlay":true,"overlay_type":"leadership","sort_order":80}];

module.exports = async (req, res) => {
  const sql = neon(process.env.DATABASE_URL);

  try {
    // Create question_bank table
    await sql`
      CREATE TABLE IF NOT EXISTS question_bank (
        id TEXT PRIMARY KEY,
        pillar TEXT NOT NULL,
        sub_category TEXT NOT NULL,
        field_name TEXT NOT NULL,
        question TEXT NOT NULL,
        description TEXT NOT NULL,
        options JSONB NOT NULL,
        is_active BOOLEAN DEFAULT true,
        is_overlay BOOLEAN DEFAULT false,
        overlay_type TEXT,
        created_at TIMESTAMPTZ DEFAULT NOW(),
        sort_order INTEGER DEFAULT 0
      )
    `;

    // Create answer_history table
    await sql`
      CREATE TABLE IF NOT EXISTS answer_history (
        id SERIAL PRIMARY KEY,
        contact_id INTEGER NOT NULL REFERENCES contacts(id),
        question_id TEXT NOT NULL REFERENCES question_bank(id),
        answer_value INTEGER NOT NULL,
        assessment_id INTEGER REFERENCES assessments(id),
        answered_at TIMESTAMPTZ DEFAULT NOW(),
        UNIQUE(contact_id, question_id)
      )
    `;

    // Create indexes
    await sql`CREATE INDEX IF NOT EXISTS idx_answer_history_contact ON answer_history(contact_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_answer_history_question ON answer_history(question_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_question_bank_pillar ON question_bank(pillar)`;

    // Create challenges table for 90-day challenge system
    await sql`
      CREATE TABLE IF NOT EXISTS challenges (
        id SERIAL PRIMARY KEY,
        contact_id INTEGER NOT NULL REFERENCES contacts(id),
        baseline_assessment_id INTEGER NOT NULL REFERENCES assessments(id),
        enrolled_at TIMESTAMPTZ DEFAULT NOW(),
        day_90_date TIMESTAMPTZ NOT NULL,
        reassessment_id INTEGER REFERENCES assessments(id),
        status TEXT DEFAULT 'active',
        UNIQUE(contact_id, baseline_assessment_id)
      )
    `;
    await sql`CREATE INDEX IF NOT EXISTS idx_challenges_contact ON challenges(contact_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_challenges_status ON challenges(status)`;

    // Create feedback table for weakness tracking
    await sql`
      CREATE TABLE IF NOT EXISTS feedback (
        id SERIAL PRIMARY KEY,
        contact_id INTEGER REFERENCES contacts(id),
        assessment_id INTEGER REFERENCES assessments(id),
        weakest_pillar TEXT NOT NULL,
        weakest_sub_categories JSONB,
        score_range TEXT,
        created_at TIMESTAMPTZ DEFAULT NOW()
      )
    `;
    await sql`CREATE INDEX IF NOT EXISTS idx_feedback_contact ON feedback(contact_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_feedback_assessment ON feedback(assessment_id)`;
    await sql`CREATE INDEX IF NOT EXISTS idx_feedback_pillar ON feedback(weakest_pillar)`;

    // Seed questions (upsert to be idempotent)
    let inserted = 0;
    let skipped = 0;
    for (const q of SEED_QUESTIONS) {
      const opts = JSON.stringify(q.options);
      const result = await sql`
        INSERT INTO question_bank (id, pillar, sub_category, field_name, question, description, options, is_overlay, overlay_type, sort_order)
        VALUES (${q.id}, ${q.pillar}, ${q.sub_category}, ${q.field_name}, ${q.question}, ${q.description}, ${opts}::jsonb, ${q.is_overlay}, ${q.overlay_type}, ${q.sort_order})
        ON CONFLICT (id) DO NOTHING
      `;
      if (result.count > 0) inserted++;
      else skipped++;
    }

    res.json({
      success: true,
      message: 'Migration complete',
      tables_created: ['question_bank', 'answer_history', 'challenges', 'feedback'],
      questions_inserted: inserted,
      questions_skipped: skipped,
      total_seed_questions: SEED_QUESTIONS.length
    });
  } catch (err) {
    console.error('Migration error:', err);
    res.status(500).json({ error: err.message });
  }
};
